import{_ as n,C as o,o as s,c as l,E as i,w as r,a as t,a0 as c}from"./chunks/framework.CkNTPv-z.js";const w=JSON.parse('{"title":"Luxembourg Legal Rights","description":"Legal rights for transgender people in Luxembourg","frontmatter":{"layout":"doc","title":"Luxembourg Legal Rights","description":"Legal rights for transgender people in Luxembourg"},"headers":[],"relativePath":"europe/luxembourg/legal-rights.md","filePath":"europe/luxembourg/legal-rights.md","lastUpdated":null}'),d={name:"europe/luxembourg/legal-rights.md"};function u(g,e,h,m,p,f){const a=o("Badge");return s(),l("div",null,[i(a,{variant:"yellow"},{default:r(()=>[...e[0]||(e[0]=[t("Self-ID since 2018",-1)])]),_:1}),i(a,{variant:"green"},{default:r(()=>[...e[1]||(e[1]=[t("Hate Crime Protections",-1)])]),_:1}),e[2]||(e[2]=c('<h1 id="legal-rights-in-luxembourg" tabindex="-1">Legal Rights in Luxembourg <a class="header-anchor" href="#legal-rights-in-luxembourg" aria-label="Permalink to &quot;Legal Rights in Luxembourg&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Luxembourg adopted a self-determination model for legal gender recognition in July 2018 (Law of 27 July 2018 on the modification of the civil code and the amended law of 10 August 1991 on the exercise of certain civil rights). The law allows individuals aged 18 and over to change their legal gender marker on official documents through a simple administrative declaration at the civil registry office.</p><p>The process requires:</p><ul><li>A written declaration of gender change</li><li>An appearance before the civil registrar</li><li>No medical certificates, surgery requirements, or psychological evaluations</li></ul><p>Minors aged 16-18 can apply with parental consent, and minors under 16 require judicial authorisation.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Legal name changes follow the gender recognition process. The same administrative declaration used to change the gender marker can include a first name change. For those who wish to change their name without changing their gender marker, a separate administrative procedure exists through the Ministry of Justice&#39;s name change process.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Luxembourg prohibits discrimination based on sex, which has been interpreted to include gender identity and gender expression. The amended Law of 28 November 2006 on equal treatment prohibits discrimination in:</p><ul><li>Employment and occupation</li><li>Access to social security and healthcare</li><li>Education</li><li>Access to goods and services</li><li>Housing</li></ul><p>The law covers direct and indirect discrimination, harassment, and instruction to discriminate.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Luxembourg&#39;s Penal Code (Article 454) includes aggravating circumstances for crimes motivated by hatred or prejudice based on sex, which courts have applied to anti-transgender violence. The law provides for enhanced penalties when an offence is committed with discriminatory motives.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>CIGALE</strong> — LGBTIQ+ support organisation: <a href="https://www.cigale.lu/" target="_blank" rel="noreferrer">cigale.lu</a></li><li><strong>Ministry of Justice</strong> — Gender recognition information: <a href="https://mj.public.lu/" target="_blank" rel="noreferrer">mj.public.lu</a></li><li><strong>Luxembourg Pride</strong> — Community events and advocacy: <a href="https://www.luxembourgpride.lu/" target="_blank" rel="noreferrer">luxembourgpride.lu</a></li><li><strong>ILGA-Europe - Luxembourg Country Report</strong> — <a href="https://www.ilga-europe.org/" target="_blank" rel="noreferrer">ilga-europe.org</a></li></ul>',16))])}const x=n(d,[["render",u]]);export{w as __pageData,x as default};
